]$part_master_seed$::jsonb) as rows(
      canonical_mpn text,
      manufacturer_name text,
      normalized_part_name text,
      datasheet_url text,
      lifecycle_status text,
      source_quality text,
      alias_names text[],
      supporting_urls text[],
      pin_schema_json jsonb,
      specs_json jsonb,
      last_synced_at timestamptz
  )
)
insert into public.part_master (canonical_mpn, manufacturer_name, normalized_part_name, datasheet_url, lifecycle_status, source_quality, alias_names, supporting_urls, pin_schema_json, specs_json, last_synced_at)
select canonical_mpn, manufacturer_name, normalized_part_name, datasheet_url, lifecycle_status, source_quality, alias_names, supporting_urls, pin_schema_json, specs_json, last_synced_at
from seed_rows
on conflict (canonical_mpn) do update set
  manufacturer_name = excluded.manufacturer_name,
  normalized_part_name = excluded.normalized_part_name,
  datasheet_url = excluded.datasheet_url,
  lifecycle_status = excluded.lifecycle_status,
  source_quality = excluded.source_quality,
  alias_names = excluded.alias_names,
  supporting_urls = excluded.supporting_urls,
  pin_schema_json = excluded.pin_schema_json,
  specs_json = excluded.specs_json,
  last_synced_at = excluded.last_synced_at;
